/**
 * Strategy Marketplace — Browse, filter, and discover validated strategies.
 * RESEARCH AND DISCOVERY ONLY — no execution.
 */
import { useState, useEffect, useCallback, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { api, apiPost } from '../utils/api';
import { tokens } from '../styles/tokens';
import GlassPanel from '../components/ui/GlassPanel';
import StatCard from '../components/ui/StatCard';
import usePageTitle from '../hooks/usePageTitle';
import s from './StrategyMarketplacePage.module.css';

const T = {
  green: tokens.color.green, red: tokens.color.red, blue: tokens.color.blue,
  amber: tokens.color.amber, purple: tokens.color.purple,
  text: tokens.color.text, textSec: tokens.color.textSecondary,
  surface2: tokens.color.surfaceHover,
};

const BADGE_STYLES = {
  high_alpha: { bg: '#1a2e1a', color: T.green, label: 'HIGH ALPHA' },
  regime_stable: { bg: '#1a2233', color: T.blue, label: 'REGIME STABLE' },
  walk_forward_validated: { bg: '#2e2a1a', color: T.amber, label: 'WF VALIDATED' },
  high_profit_factor: { bg: '#1a2e1a', color: T.green, label: 'HIGH PF' },
  trusted: { bg: '#1a2233', color: T.purple, label: 'TRUSTED' },
  popular: { bg: '#2e2a1a', color: T.amber, label: 'POPULAR' },
};

function Badge({ name }) {
  const b = BADGE_STYLES[name] || { bg: T.surface2, color: T.textSec, label: name };
  return (
    <span className={s.badge} style={{ background: b.bg, color: b.color }}>
      {b.label}
    </span>
  );
}

function MiniBar({ value, max = 1, color = T.blue, width = 50 }) {
  const pct = Math.min(Math.max(value / max, 0), 1) * 100;
  return (
    <div className={s.miniBarTrack} style={{ width }}>
      <div className={s.miniBarFill} style={{ width: `${pct}%`, background: color }} />
    </div>
  );
}

export default function StrategyMarketplacePage() {
  usePageTitle('Strategy Marketplace');
  const navigate = useNavigate();

  const [strategies, setStrategies] = useState([]);
  const [total, setTotal] = useState(0);
  const [categories, setCategories] = useState(null);
  const [featured, setFeatured] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [familyFilter, setFamilyFilter] = useState('');
  const [dirFilter, setDirFilter] = useState('');
  const [sortBy, setSortBy] = useState('alpha_score');
  const [minAlpha, setMinAlpha] = useState(0);

  const fetchData = useCallback(async () => {
    const params = new URLSearchParams({ sort_by: sortBy, limit: '60', min_alpha: String(minAlpha) });
    if (familyFilter) params.set('family', familyFilter);
    if (dirFilter) params.set('direction', dirFilter);

    const [strats, cats, feat] = await Promise.all([
      api(`/api/marketplace/catalog/strategies?${params}`),
      api('/api/marketplace/catalog/categories'),
      api('/api/marketplace/catalog/featured'),
    ]);
    if (strats) { setStrategies(strats.strategies || []); setTotal(strats.total || 0); }
    if (cats) setCategories(cats);
    if (feat) setFeatured(feat.strategies || []);
    setLoading(false);
  }, [sortBy, familyFilter, dirFilter, minAlpha]);

  useEffect(() => { fetchData(); }, [fetchData]);

  const filtered = useMemo(() => {
    if (!search) return strategies;
    const q = search.toLowerCase();
    return strategies.filter(st =>
      st.strategy_id?.toLowerCase().includes(q) ||
      st.strategy_name?.toLowerCase().includes(q) ||
      st.family?.toLowerCase().includes(q)
    );
  }, [strategies, search]);

  const doAction = async (sid, action) => {
    await apiPost('/api/marketplace/catalog/action', { strategy_id: sid, action });
    fetchData();
  };

  if (loading) return <div className={s.loadingState}>Loading marketplace...</div>;

  const families = Object.entries(categories?.families || {}).sort((a, b) => b[1] - a[1]);

  return (
    <div className={s.page}>
      <div className={s.header}>
        <h1 className={s.title}>Strategy Marketplace</h1>
        <p className={s.subtitle}>Browse validated strategies — research and discovery only</p>
      </div>

      {/* Stats */}
      <div className={s.statsGrid}>
        <StatCard label="Total Listed" value={total} accentColor={T.blue} compact />
        <StatCard label="Featured" value={featured.length} accentColor={T.amber} compact />
        <StatCard label="Families" value={families.length} accentColor={T.green} compact />
      </div>

      {/* Filters */}
      <GlassPanel className={s.filtersPanel}>
        <div className={s.filtersRow}>
          <input
            type="text"
            placeholder="Search strategies..."
            value={search}
            onChange={e => setSearch(e.target.value)}
            className={s.searchInput}
          />
          <select value={familyFilter} onChange={e => setFamilyFilter(e.target.value)} className={s.filterSelect}>
            <option value="">All families</option>
            {families.map(([f]) => <option key={f} value={f}>{f} ({categories?.families[f]})</option>)}
          </select>
          <select value={dirFilter} onChange={e => setDirFilter(e.target.value)} className={s.filterSelect}>
            <option value="">All directions</option>
            <option value="long">Long</option>
            <option value="short">Short</option>
          </select>
          <select value={sortBy} onChange={e => setSortBy(e.target.value)} className={s.filterSelect}>
            <option value="alpha_score">Alpha Score</option>
            <option value="reputation_score">Reputation</option>
            <option value="sharpe">Sharpe</option>
            <option value="regime_stability">Stability</option>
            <option value="popular">Popular</option>
            <option value="recent">Recent</option>
          </select>
        </div>
      </GlassPanel>

      {/* Strategy Grid */}
      <div className={s.strategyGrid}>
        {filtered.map(st => (
          <GlassPanel
            key={st.strategy_id}
            hover
            onClick={() => navigate(`/strategy-marketplace/${st.strategy_id}`)}
            className={s.strategyCard}
          >
            <div className={s.cardHeader}>
              <div>
                <div className={s.cardName}>{st.strategy_name || st.strategy_id}</div>
                <div className={s.cardMeta}>{st.family} · {st.direction}</div>
              </div>
              <div
                className={s.alphaScore}
                style={{ color: st.alpha_score >= 0.7 ? T.green : st.alpha_score >= 0.5 ? T.amber : T.text }}
              >
                {(st.alpha_score || 0).toFixed(2)}
              </div>
            </div>

            {/* Metrics row */}
            <div className={s.metricsRow}>
              {[
                { label: 'Sharpe', value: (st.sharpe || 0).toFixed(2), color: st.sharpe >= 1.5 ? T.green : T.text },
                { label: 'PF', value: (st.profit_factor || 0).toFixed(2), color: st.profit_factor >= 1.4 ? T.green : T.text },
                { label: 'WR', value: `${(st.win_rate || 0).toFixed(0)}%`, color: T.text },
                { label: 'DD', value: `${((st.max_drawdown || 0) * 100).toFixed(0)}%`, color: st.max_drawdown < -0.25 ? T.red : T.text },
              ].map(m => (
                <div key={m.label} className={s.metricCell}>
                  <div className={s.metricValue} style={{ color: m.color }}>{m.value}</div>
                  <div className={s.metricLabel}>{m.label}</div>
                </div>
              ))}
            </div>

            {/* Stability + WF bars */}
            <div className={s.barsRow}>
              <div className={s.barCol}>
                <div className={s.barLabel}>Regime Stability</div>
                <MiniBar value={st.regime_stability_score || 0} color={T.blue} width="100%" />
              </div>
              <div className={s.barCol}>
                <div className={s.barLabel}>Walk-Forward</div>
                <MiniBar value={st.walk_forward_score || 0} color={T.green} width="100%" />
              </div>
            </div>

            {/* Badges */}
            {st.badges?.length > 0 && (
              <div className={s.badgesRow}>
                {st.badges.slice(0, 4).map(b => <Badge key={b} name={b} />)}
              </div>
            )}

            {/* Action row */}
            <div className={s.actionRow}>
              <button
                onClick={e => { e.stopPropagation(); doAction(st.strategy_id, 'add_watchlist'); }}
                className={s.watchlistBtn}
              >
                + Watchlist
              </button>
              <button
                onClick={e => { e.stopPropagation(); doAction(st.strategy_id, 'add_bookmark'); }}
                className={s.bookmarkBtn}
              >
                Bookmark
              </button>
              <span className={s.repScore}>
                {st.reputation_score ? `Rep: ${st.reputation_score.toFixed(2)}` : ''}
              </span>
            </div>
          </GlassPanel>
        ))}
      </div>

      {filtered.length === 0 && (
        <GlassPanel className={s.emptyPanel}>
          <div className={s.emptyText}>
            No strategies match your filters. Try syncing the catalog first.
          </div>
        </GlassPanel>
      )}
    </div>
  );
}
